krpano.action:
delayedcall(0.5,
    if(plugin[soundinterface],
        playsound(bgmusic, 'add_hotspot/sound/nhacnen.mp3', 1, 0.25);
        trace("AM THANH: Da phat nhac nen");
      ,
        trace("AM THANH: Khong tim thay plugin soundinterface");
    );
);

if(startscene === null OR !scene[get(startscene)], copy(startscene,scene[0].name); );


if(startscene == scene_1,
	set(scene_1_allow_intro_once, true);
  ,
	set(scene_1_allow_intro_once, false);
);

loadscene(get(startscene), null, MERGE);
if(startactions !== null, startactions() );


calc(local.xframes, (caller.imagewidth /framewidth) BOR 0);
calc(local.frames, xframes * ((caller.imageheight / frameheight) BOR 0));
def(local.frame, integer, 0);


calc(caller.crop, '0|0|' + framewidth + '|' + frameheight);


setinterval(calc('crop_anim_' + caller.name), calc(1.0 / framerate),
	if(caller.loaded,
		inc(frame);
		if(frame GE frames, if(caller.onlastframe !== null, callwith(caller, onlastframe() ) ); set(frame,0); );
		mod(xpos, frame, xframes);
		div(ypos, frame, xframes);
		Math.floor(ypos);
		mul(xpos, framewidth);
		mul(ypos, frameheight);
		calc(caller.crop, xpos + '|' + ypos + '|' + framewidth + '|' + frameheight);
	  ,

		clearinterval(calc('crop_anim_' + caller.name));
	);
);


calc(local.xframes, (caller.imagewidth /framewidth) BOR 0);
calc(local.frames, xframes * ((caller.imageheight / frameheight) BOR 0));
def(local.frame, integer, 0);


calc(caller.crop, '0|0|' + framewidth + '|' + frameheight);


setinterval(calc('crop_anim_' + caller.name), calc(1.0 / framerate),
	if(caller.loaded,
		inc(frame);
		if(frame GE frames, if(caller.onlastframe !== null, callwith(caller, onlastframe() ) ); set(frame,0); );
		mod(xpos, frame, xframes);
		div(ypos, frame, xframes);
		Math.floor(ypos);
		mul(xpos, framewidth);
		mul(ypos, frameheight);
		calc(caller.crop, xpos + '|' + ypos + '|' + framewidth + '|' + frameheight);
	  ,

		clearinterval(calc('crop_anim_' + caller.name));
	);
);

set(caller.oy, 0);
set(caller.scale, 0.25);
set(caller.alpha, 0.0);

tween(caller.alpha, 1.0, 0.6);
tween(caller.oy, -20, 0.6);
tween(caller.scale, 0.2, 0.6, linear, 

    tween(caller.alpha, 0.0, 0.6);
    tween(caller.oy, -40, 0.6);
    tween(caller.scale, 0.125, 0.6, linear,

        if(caller.loaded, flow_arrow_anim() );
    );
);

set(caller.oy, 0);
set(caller.alpha, 0.0);
set(caller.scale, 0.25); tween(caller.alpha, 1.0, 1.0);
tween(caller.oy, -20, 1.0, linear, 

    tween(caller.alpha, 0.0, 1.0);
    tween(caller.oy, -40, 1.0, linear,
        if(caller.loaded, flow_smooth_anim() );
    );
);

calc(local.oy_target, caller.oy_base - 10);

tween(caller.oy, get(oy_target), 0.6, easeOutQuad,
    tween(caller.oy, get(caller.oy_base), 0.6, easeInQuad,
        if(caller.loaded, wave_ripple_anim() );
    );
);

tween(scale, 0.3, 0.8, easeInOutSine);
tween(alpha, 0.7, 0.8, easeInOutSine, 
    tween(scale, 0.35, 0.8, easeInOutSine);
    tween(alpha, 1.0, 0.8, easeInOutSine, 
        animate_arrow_bounce_2();
    );
);

tween(scale, 0.3, 0.8, easeInOutSine);
tween(alpha, 0.7, 0.8, easeInOutSine, 
    tween(scale, 0.35, 0.8, easeInOutSine);
    tween(alpha, 1.0, 0.8, easeInOutSine, 
        animate_arrow_bounce_2();
    );
);


tween(caller.oy, -10, 0.5, easeOutQuad, 
    tween(caller.oy, 0, 0.5, easeInQuad, arrow_sliding() )
);


tween(caller.scale, 1.05, 0.8, easeOutSine);
tween(caller.alpha, 0.7, 0.8, easeOutSine, 
    tween(caller.scale, 1.0, 0.8, easeInSine);
    tween(caller.alpha, 1.0, 0.8, easeInSine, arrow_breathing() );
);


set(temp_video_url, %1);

txtreplace(temp_video_url, '%FIRSTXML%/', get(xml.url));

set(plugin[video_popup].visible, true);
set(layer[close_video].visible, true);

plugin[video_popup].playvideo(get(temp_video_url));

if(scene_1_allow_intro_once == true,
    set(scene_1_allow_intro_once, false);
    intro_high_start();
  ,
    set(intro_tour_started, true);
    viewflycam_after_intro();
);

set(is_scene_opening, false);
stop_scene_right_rotate();


set(layer[intro_ui].alpha, 0);
set(layer[intro_ui].visible, false);


stoptween(view.hlookat);
stoptween(view.vlookat);
stoptween(view.fov);
stoptween(view.fisheye);


set(view.fovtype, MFOV);
set(view.hlookat, 0.0);
set(view.vlookat, 35.0);
set(view.fov, 140);
set(view.fisheye, 0.0);
set(view.stereographic, false);
set(view.limitview, auto);

set(scene_1_allow_intro_once, false);
set(intro_tour_started, true);
set(is_scene_opening, false);
stop_scene_right_rotate();

stoptween(view.fov);
stoptween(view.hlookat);
stoptween(view.vlookat);

loadscene(scene_1, view.hlookat=0.0&view.vlookat=35.0&view.fov=140&view.fisheye=0.0&view.stereographic=false&view.limitview=auto, MERGE, BLEND(0.5));

delayedcall(0.12, viewflycam_after_intro(););
delayedcall(0.38, viewflycam_after_intro(););

if(newscene == scene_1,
    open_viewflycam_like_first();
  ,
    if(skin_settings.loadscene_flags == null, set(skin_settings.loadscene_flags, MERGE););
    if(blendmode == null, copy(blendmode, skin_settings.loadscene_blend););
    loadscene(get(newscene), null, get(skin_settings.loadscene_flags), get(blendmode));
);

skin_updatescroll();

set(layer[intro_ui].visible, true);
set(layer[intro_ui].alpha, 0);


play_bg_sound();


tween(layer[intro_ui].alpha, 1, 0.8, easeOutQuad);


delayedcall(0.15,
    tween(layer[intro_title_brush].alpha, 1, 0.55, easeOutQuad);
    tween(layer[intro_title].alpha, 1, 0.55, easeOutQuad);
    tween(layer[intro_subtitle].alpha, 1, 0.65, easeOutQuad);
);


delayedcall(0.40,
    tween(layer[intro_card_left_1].alpha, 1, 0.55, easeOutQuad);
    tween(layer[intro_card_left_2].alpha, 1, 0.65, easeOutQuad);
    tween(layer[intro_card_right_1].alpha, 1, 0.55, easeOutQuad);
    tween(layer[intro_card_right_2].alpha, 1, 0.65, easeOutQuad);
);


delayedcall(0.65,
    tween(layer[intro_pin].alpha, 1, 0.5, easeOutQuad);
    tween(layer[intro_plane].alpha, 1, 0.5, easeOutQuad);
);


delayedcall(0.95,
    tween(layer[intro_cta].alpha, 1, 0.5, easeOutQuad);
);


tween(view.hlookat, 15, 8.0, linear);


set(intro_tour_started, true);


tween(layer[intro_ui].alpha, 0, 0.45, easeOutQuad);


tween(view.vlookat, 35, 0.95, easeInOutCubic);
tween(view.fov, 140, 0.95, easeInOutCubic);
tween(view.fisheye, 0.0, 0.95, easeInOutCubic);


delayedcall(0.00,
    stop_scene_right_rotate();
    tween(view.hlookat, 0.0, 0.95, easeInOutCubic);
);

delayedcall(1.05,
    set(layer[intro_ui].visible, false);
    set(view.hlookat, 0.0);
    set(view.vlookat, 35.0);
    set(view.fov, 140);
    set(view.fisheye, 0.0);
    set(view.stereographic, false);
    set(view.limitview, auto);
);


set(scene_right_rotating, false);


set(autorotate.enabled, false);


stoptween(view.hlookat);


set(layer[btn_stop_rotate].visible, false);


if(is_scene_opening == true, exit(););
set(is_scene_opening, true);


stoptween(view.fov);
stoptween(view.hlookat);
stoptween(view.vlookat);


if(layer[scene_open_cover],
    stoptween(layer[scene_open_cover].alpha);
    set(layer[scene_open_cover].alpha, 0);
    set(layer[scene_open_cover].visible, false);
    removelayer(scene_open_cover);
);


loadscene(get(scenename), null, MERGE, BLEND(0.25));


delayedcall(0.08,

    copy(target_hlookat, view.hlookat);
    copy(target_vlookat, view.vlookat);
    copy(target_fov, view.fov);


    calc(start_fov, target_fov + 22);

    if(start_fov GT view.fovmax,
        copy(start_fov, view.fovmax);
    );

    calc(start_vlookat, target_vlookat - 8);

    set(view.fov, get(start_fov));
    set(view.vlookat, get(start_vlookat));


    tween(view.fov, get(target_fov), 3, easeOutCubic);
    tween(view.vlookat, get(target_vlookat), 3, easeOutCubic);

    delayedcall(1.20,
        set(is_scene_opening, false);
    );
);

if(ripple_image == null, set(ripple_image, 'hs_circle.png'));
if(base_scale == null, set(base_scale, 0.2));

txtadd(ripple_name, get(caller.name), '_universal_ripple');
addhotspot(get(ripple_name));

set(hotspot[get(ripple_name)].url, get(ripple_image));

set(hotspot[get(ripple_name)].ath, get(caller.ath));
set(hotspot[get(ripple_name)].atv, get(caller.atv));
set(hotspot[get(ripple_name)].edge, center); 

copy(hotspot[get(ripple_name)].flying, caller.flying); 
copy(hotspot[get(ripple_name)].distorted, caller.distorted);
copy(hotspot[get(ripple_name)].rx, caller.rx);
copy(hotspot[get(ripple_name)].ry, caller.ry);
copy(hotspot[get(ripple_name)].rz, caller.rz);
copy(hotspot[get(ripple_name)].ox, caller.ox);
copy(hotspot[get(ripple_name)].oy, caller.oy);

set(hotspot[get(ripple_name)].zorder, 10); 
set(hotspot[get(ripple_name)].enabled, false); 

universal_ripple_loop(get(ripple_name), get(base_scale));

set(hotspot[get(hs_name)].scale, get(base_scale));
set(hotspot[get(hs_name)].alpha, 0.4);

calc(target_scale, base_scale * 2.5);

tween(hotspot[get(hs_name)].scale, get(target_scale), 1.5, easeOutQuad);
tween(hotspot[get(hs_name)].alpha, 0.0, 1.5, easeOutQuad,
    if(hotspot[get(hs_name)].loaded, 
        universal_ripple_loop(get(hs_name), get(base_scale)); 
    );
);
